CREATE TABLE "HealthBillingServiceCatalog" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"code" TEXT NOT NULL,"labelFr" TEXT NOT NULL,"labelEn" TEXT,"category" TEXT NOT NULL,"defaultPrice" DECIMAL(14,2) NOT NULL,"currency" TEXT NOT NULL DEFAULT 'CDF',"billable" BOOLEAN NOT NULL DEFAULT true,"requiresMedicalContext" BOOLEAN NOT NULL DEFAULT false,"isGlobal" BOOLEAN NOT NULL DEFAULT false,"isActive" BOOLEAN NOT NULL DEFAULT true,"sortOrder" INTEGER NOT NULL DEFAULT 0,"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "HealthBillingServiceCatalog_pkey" PRIMARY KEY ("id"));
CREATE TABLE "HealthMedicalInvoice" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"legacyRecordId" TEXT,"invoiceNumber" TEXT NOT NULL,"patientId" TEXT NOT NULL,"consultationId" TEXT,"appointmentId" TEXT,"labRequestId" TEXT,"pharmacyDispensationId" TEXT,"departmentId" TEXT,"invoiceType" TEXT NOT NULL,"invoiceDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"dueDate" TIMESTAMP(3),"currency" TEXT NOT NULL DEFAULT 'CDF',"status" TEXT NOT NULL DEFAULT 'DRAFT',"subtotalAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"discountAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"discountReason" TEXT,"taxAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"insuranceAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"patientAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"totalAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"paidAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"balanceAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"notesInternal" TEXT,"notesVisible" TEXT,"createdById" TEXT NOT NULL,"updatedById" TEXT,"issuedById" TEXT,"issuedAt" TIMESTAMP(3),"cancelledById" TEXT,"cancelledAt" TIMESTAMP(3),"cancellationReason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "HealthMedicalInvoice_pkey" PRIMARY KEY ("id"));
CREATE TABLE "HealthMedicalInvoiceItem" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"invoiceId" TEXT NOT NULL,"itemType" TEXT NOT NULL,"serviceCatalogId" TEXT,"description" TEXT NOT NULL,"quantity" DECIMAL(14,3) NOT NULL,"unitPrice" DECIMAL(14,2) NOT NULL,"discountAmount" DECIMAL(14,2) NOT NULL DEFAULT 0,"totalAmount" DECIMAL(14,2) NOT NULL,"linkedConsultationId" TEXT,"linkedLabRequestId" TEXT,"linkedPharmacyDispensationId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "HealthMedicalInvoiceItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "HealthMedicalInvoicePayment" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"invoiceId" TEXT NOT NULL,"amount" DECIMAL(14,2) NOT NULL,"paymentDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"paymentMethod" TEXT NOT NULL,"paymentReference" TEXT,"receiptNumber" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'CONFIRMED',"comment" TEXT,"collectedById" TEXT NOT NULL,"cancelledById" TEXT,"cancelledAt" TIMESTAMP(3),"cancellationReason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "HealthMedicalInvoicePayment_pkey" PRIMARY KEY ("id"));
CREATE TABLE "HealthMedicalInvoiceEvent" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"invoiceId" TEXT NOT NULL,"eventType" TEXT NOT NULL,"summary" TEXT NOT NULL,"fromStatus" TEXT,"toStatus" TEXT,"metadataJson" JSONB,"actorUserId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "HealthMedicalInvoiceEvent_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX IF NOT EXISTS "HealthPharmacyDispensation_organizationId_id_key" ON "HealthPharmacyDispensation"("organizationId","id");
CREATE UNIQUE INDEX "HealthBillingServiceCatalog_organizationId_code_key" ON "HealthBillingServiceCatalog"("organizationId","code"); CREATE UNIQUE INDEX "HealthBillingServiceCatalog_organizationId_id_key" ON "HealthBillingServiceCatalog"("organizationId","id");
