CREATE UNIQUE INDEX "HealthMedicalInvoice_organizationId_consultationId_key" ON "HealthMedicalInvoice"("organizationId","consultationId"); CREATE UNIQUE INDEX "HealthMedicalInvoice_organizationId_labRequestId_key" ON "HealthMedicalInvoice"("organizationId","labRequestId"); CREATE UNIQUE INDEX "HealthMedicalInvoice_organizationId_pharmacyDispensationId_key" ON "HealthMedicalInvoice"("organizationId","pharmacyDispensationId");
CREATE UNIQUE INDEX "HealthMedicalInvoiceItem_organizationId_linkedConsultationId_key" ON "HealthMedicalInvoiceItem"("organizationId","linkedConsultationId"); CREATE UNIQUE INDEX "HealthMedicalInvoiceItem_organizationId_linkedLabRequestId_key" ON "HealthMedicalInvoiceItem"("organizationId","linkedLabRequestId"); CREATE UNIQUE INDEX "HealthMedicalInvoiceItem_organizationId_linkedPharmacyDispensationId_key" ON "HealthMedicalInvoiceItem"("organizationId","linkedPharmacyDispensationId"); CREATE INDEX "HealthMedicalInvoiceItem_organizationId_invoiceId_idx" ON "HealthMedicalInvoiceItem"("organizationId","invoiceId");
CREATE UNIQUE INDEX "HealthMedicalInvoicePayment_organizationId_receiptNumber_key" ON "HealthMedicalInvoicePayment"("organizationId","receiptNumber"); CREATE INDEX "HealthMedicalInvoicePayment_organizationId_invoiceId_paymentDate_idx" ON "HealthMedicalInvoicePayment"("organizationId","invoiceId","paymentDate"); CREATE INDEX "HealthMedicalInvoiceEvent_organizationId_invoiceId_createdAt_idx" ON "HealthMedicalInvoiceEvent"("organizationId","invoiceId","createdAt");
