UPDATE "EnterprisePosition" SET "permissionsJson"=COALESCE("permissionsJson",'[]'::jsonb)||'["health.billing.view","health.billing.view_sensitive","health.billing.create_invoice","health.billing.update_invoice","health.billing.issue_invoice","health.billing.cancel_invoice","health.billing.record_payment","health.billing.cancel_payment","health.billing.apply_discount","health.billing.apply_large_discount","health.billing.manage_catalog","health.billing.export_invoice","health.billing.view_reports"]'::jsonb WHERE "positionCode" IN ('MEDICAL_DIRECTOR','MEDICAL_CASHIER') AND "sectorId" IN (SELECT "id" FROM "BusinessSector" WHERE "code"='HEALTH_CARE');
